@modal.web_endpoint(method="POST")
def predict(self, body: dict) -> dict:
    """Accept JSON with an 'inputs' field and return predictions."""
    import numpy as np

    inputs = body.get("inputs", [])
    if not inputs:
        return {"error": "No inputs provided", "predictions": []}

    x = np.array(inputs, dtype=float)

    # Simple linear projection using first row of weight matrix
    row = self.weights[0, : len(x)] if len(x) <= self.weights.shape[1] else self.weights[0]
    predictions = (x * row[: len(x)]).tolist()

    return {
        "predictions": predictions,
        "model_version": self.model_version,
        "weights_shape": list(self.weights.shape),
    }

@modal.method()
def run_inference(self, inputs: list) -> dict:
    """Remote-callable method that runs inference; used by the local entrypoint."""
    return self.predict({"inputs": inputs})

